// services/bundle-service.js
// Bundle (multi-file share link) business logic. Routes stay thin; logic lives here.

const crypto = require('crypto');
const { query } = require('./database');
const storage = require('./storage');
const { deleteThumb } = require('./storage-service');

const SALT_LENGTH = 16; // matches crypto.js client (PBKDF2 salt)

/**
 * Create an empty bundle (no files yet). The bundle id is generated by the DB
 * (uuid_generate_v4 default) and read back via RETURNING; the password_salt is
 * generated client-side and also read back. expire_at is derived server-side
 * from expireHours (NOW() + hours * interval) so the stored column is the real
 * timestamp and the param stays the raw hour count — matching Task 1's schema
 * (bundles has expire_at, NOT expire_hours; password_salt, NOT password).
 * password_salt is NULL when no password is given, so legacy/backfilled bundles
 * fall back to per-file salt on decrypt.
 *
 * @returns {Promise<{id: string, passwordSalt: string|null}>}
 */
async function createBundle(sessionId, { expireHours, title = null, password = null } = {}) {
  const hours = Math.max(1, parseInt(expireHours, 10) || 1);
  const isEncrypted = !!password;
  const passwordSalt = password ? crypto.randomBytes(SALT_LENGTH).toString('base64') : null;

  const res = await query(
    `INSERT INTO bundles (session_id, title, expire_at, is_encrypted, password_salt)
     VALUES ($1, $2, NOW() + ($3 * interval '1 hour'), $4, $5)
     RETURNING id, password_salt`,
    [sessionId, title, hours, isEncrypted, passwordSalt]
  );
  return { id: res.rows[0].id, passwordSalt: res.rows[0].password_salt };
}

/**
 * Attach a finished file to a bundle and bump aggregate counters.
 */
async function addFileToBundle(fileId, bundleId, fileSize) {
  await query(`UPDATE files SET bundle_id = $1 WHERE id = $2`, [bundleId, fileId]);
  await query(`UPDATE bundles SET file_count = file_count + 1, total_size = total_size + $2 WHERE id = $1`, [bundleId, fileSize || 0]);
}

/**
 * Fetch a bundle + its files for the receiver page.
 * @returns {Promise<Object|null>} { ...bundle, expired, files: [...] }
 */
async function getBundle(bundleId) {
  const bRes = await query(
    `SELECT id, session_id, title, file_count, total_size, expire_at,
            is_encrypted, password_salt, created_at
       FROM bundles WHERE id = $1`,
    [bundleId]
  );
  if (bRes.rows.length === 0) return null;

  const bundle = bRes.rows[0];
  const expired = new Date(bundle.expire_at) < new Date();

  const fRes = await query(
    `SELECT id, filename, file_size, mime_type, is_encrypted,
            encryption_iv, encryption_salt, created_at, download_count,
            storage_backend, storage_key
       FROM files WHERE bundle_id = $1 ORDER BY created_at ASC`,
    [bundleId]
  );

  return { ...bundle, expired, files: fRes.rows };
}

/**
 * Page a user's own bundles for "Dosyalarım".
 */
async function getMyBundles(sessionId, { page = 1, limit = 20 } = {}) {
  const p = Math.max(1, parseInt(page, 10) || 1);
  const l = Math.min(100, Math.max(1, parseInt(limit, 10) || 20));
  const offset = (p - 1) * l;

  const totalRes = await query(`SELECT COUNT(*)::int AS total FROM bundles WHERE session_id = $1`, [sessionId]);
  const total = totalRes.rows[0].total;

  const res = await query(
    `SELECT id, title, file_count, total_size, expire_at, is_encrypted, created_at
       FROM bundles WHERE session_id = $1
       ORDER BY created_at DESC
       LIMIT $2 OFFSET $3`,
    [sessionId, l, offset]
  );

  return { bundles: res.rows, page: p, limit: l, total, pages: Math.max(1, Math.ceil(total / l)) };
}

/**
 * Delete a bundle AND its storage objects (cascade only removes DB rows, not blobs).
 * Ownership-checked against sessionId. Matches cleanupExpiredBundles' pattern:
 *   1. fetch the bundle's files (storage_backend + storage_key)
 *   2. delete each object from its backend (error → log + continue, orphan blob)
 *   3. delete each thumbnail cache (local, best-effort)
 *   4. delete the bundle row → FK ON DELETE CASCADE removes files rows
 * Without step 1-3 the physical blob is orphaned in the bucket (only the DB row dies).
 * @returns {Promise<boolean>} true if deleted, false if not owner / not found
 */
async function deleteBundle(bundleId, sessionId) {
  // Önce sahiplik doğrula + bundle'ın dosyalarını çek (silmeden önce, çünkü
  // cascade files satırlarını yok eder — o noktadan sonra storage_key kaybolur).
  const filesRes = await query(
    `SELECT f.id, f.storage_backend, f.storage_key
     FROM files f
     JOIN bundles b ON b.id = f.bundle_id
     WHERE b.id = $1 AND b.session_id = $2`,
    [bundleId, sessionId]
  );

  // Sahip değil veya bundle yok → hiçbir şey silme.
  // (filesRes boş olabilir çünkü (a) sahip değil / yok, (b) sahip ama dosya yok.
  //  Ayırt etmek için bundle satırını ayrıca kontrol et.)
  if (filesRes.rows.length === 0) {
    const owns = await query(
      `SELECT 1 FROM bundles WHERE id = $1 AND session_id = $2`,
      [bundleId, sessionId]
    );
    if ((owns.rowCount || 0) === 0) return false; // sahip değil / bulunamadı
    // sahip ama dosya yok → sadece bundle satırını sil (object yok)
    const del = await query(
      `DELETE FROM bundles WHERE id = $1 AND session_id = $2`,
      [bundleId, sessionId]
    );
    return (del.rowCount || 0) > 0;
  }

  // Storage object'lerini sil (dosyanın KENDİ backend'ine göre).
  // Hata olsa bile DB silmeye devam et — orphan blob logla (cleanup-job deseni).
  for (const f of filesRes.rows) {
    if (f.storage_key) {
      try {
        const provider = await storage.getProviderForFile(f);
        await provider.deleteObject(f.storage_key);
      } catch (err) {
        console.error(`[BundleDelete] Error deleting object ${f.storage_key} from ${f.storage_backend}:`, err.message);
        // orphan blob — devam et
      }
    }
    // Thumbnail cache (image dosyaları, her zaman local disk)
    try { await deleteThumb(f.id); } catch { /* thumbnail yoksa kritik değil */ }
  }

  // Bundle satırını sil → FK ON DELETE CASCADE files satırlarını da kaldırır.
  const res = await query(
    `DELETE FROM bundles WHERE id = $1 AND session_id = $2`,
    [bundleId, sessionId]
  );
  return (res.rowCount || 0) > 0;
}

/**
 * Pure helper: which salt does the client use to decrypt a given file in a bundle?
 * New bundles share one salt (bundle.password_salt); backfilled/legacy files keep
 * their per-file salt (file.encryption_salt). This preserves legacy passwords.
 */
function selectDecryptSalt(bundle, file) {
  if (bundle && bundle.password_salt) return bundle.password_salt;
  return (file && file.encryption_salt) || null;
}

module.exports = {
  createBundle,
  addFileToBundle,
  getBundle,
  getMyBundles,
  deleteBundle,
  selectDecryptSalt,
};
